fun solve(nums: Array<Long>): Long {
    val sorted = nums.map { Math.abs(it) }.sorted()
    var total = 0L
    for (i in 0 until sorted.size - 1) {
        val target = 2 * sorted[i]
        var low = i + 1
        var high = sorted.size - 1
        var res = sorted.size
        while (low <= high) {
            val mid = (low + high) / 2
            if (sorted[mid] > target) {
                res = mid
                high = mid - 1
            } else {
                low = mid + 1
            }
        }
        total += (res - (i + 1)).toLong()
    }
    return total
}
